use jsonwebtoken::{decode, Algorithm};

fn verify_jwt(token: &str) -> Result<UserInfo, jsonwebtoken::errors::Error> {
    let decoded_token = decode(token, None, &[Algorithm::RS256])?;
    let claims = decoded_token.claims;
    let user_id = claims.get("user_id").unwrap().as_str().unwrap();
    let name = claims.get("name").unwrap().as_str().unwrap();
    let email = claims.get("email").unwrap().as_str().unwrap();

    Ok(UserInfo { user_id, name, email })
}